---
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
}

const { class: className = "", ...rest } = Astro.props as Props;

const contentWrapperVariants = cva(
  "grid grid-rows-[0fr] transition-[grid-template-rows] duration-150 ease-in-out group-data-[state=open]/accordion:grid-rows-[1fr]",
);

const contentVariants = cva("overflow-hidden min-h-0 [&[hidden]]:!block");

const contentInnerVariants = cva("");
---

<div class={cn("group/accordion", className)} {...rest}>
  <div class={cn(contentWrapperVariants())}>
    <div
      data-slot="accordion-content"
      class={cn("data-open:animate-accordion-down data-closed:animate-accordion-up text-sm", contentVariants())}
    >
      <div class={cn("pt-0 pb-4", contentInnerVariants(), className)}>
        <slot />
      </div>
    </div>
  </div>
</div>

---
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"details"> {
  value: string;
  open?: boolean;
  class?: string;
}

const {
  value,
  open = false,
  class: className = "",
  ...rest
} = Astro.props as Props;

const itemVariants = cva("");
---

<div
  {...rest}
  data-value={value}
  data-slot="accordion-item"
  class={cn("not-last:border-b", itemVariants(), "group/accordion", className)}
>
  <slot />
</div>

---
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
  /** Radix-like: render wrapper so the child can be the interactive element */
  asChild?: boolean;
}

const { class: className = "", asChild = false, type = "button", ...rest } = Astro.props as Props;

const triggerVariants = cva(
  "w-full flex flex-1 items-start justify-between outline-none transition-all disabled:pointer-events-none disabled:opacity-50 [&[aria-expanded=true]>svg]:rotate-180",
);
---

{
  asChild ? (
    <div
      data-slot="accordion-trigger"
      data-as-child
      class={cn("focus-visible:ring-ring/50 focus-visible:border-ring focus-visible:after:border-ring **:data-[slot=accordion-trigger-icon]:text-muted-foreground rounded-md py-4 text-left text-sm font-medium hover:underline focus-visible:ring-3 **:data-[slot=accordion-trigger-icon]:ml-auto **:data-[slot=accordion-trigger-icon]:size-4", triggerVariants(), className)}
    >
      <slot />
    </div>
  ) : (
    <button
      {...rest}
      type={type}
      data-slot="accordion-trigger"
      class={cn("focus-visible:ring-ring/50 focus-visible:border-ring focus-visible:after:border-ring **:data-[slot=accordion-trigger-icon]:text-muted-foreground rounded-md py-4 text-left text-sm font-medium hover:underline focus-visible:ring-3 **:data-[slot=accordion-trigger-icon]:ml-auto **:data-[slot=accordion-trigger-icon]:size-4", triggerVariants(), className)}
    >
      <span class="flex-1">
        <slot />
      </span>
      {
        Astro.slots.has("icon") ? (
          <span
            data-slot="accordion-trigger-icon"
            class="inline-flex items-center justify-center transition-transform duration-200 group-open/accordion:rotate-180"
          >
            <slot name="icon" />
          </span>
        ) : (
          <SemanticIcon
            name="chevron-down"
            data-slot="accordion-trigger-icon"
            class="shrink-0 transition-transform duration-200 group-open/accordion:rotate-180"
            aria-hidden="true"
          />
        )
      }
    </button>
  )
}

export { default as Accordion } from "./Accordion.astro";
export { default as AccordionItem } from "./AccordionItem.astro";
export { default as AccordionTrigger } from "./AccordionTrigger.astro";
export { default as AccordionContent } from "./AccordionContent.astro";
